args.sparql:
SELECT ?player ?yards
WHERE {
  ?player rdfs:label "Norm Van Brocklin"@en;
         wdt:P31 wd:Q5;
         wdt:P106 wd:Q19204627;  # American football player
         ?statProperty ?stat.
  ?stat a wikibase:QuantityValue;
        wikibase:quantityAmount ?yards;
        wikibase:quantityUnit wd:Q202029.  # yards unit
  FILTER(?yards > 500)
}
ORDER BY DESC(?yards)
LIMIT 1
